onClipEvent (enterFrame) {
   //_parent.攻击时斜向移动(-20,-25);
   _parent.攻击时移动(-25,-30);
}

onClipEvent(load){
   if(_root.是否阴影 == true)
   {
      this._visible = 1;
   }
   else
   {
      this._visible = 0;
   }
}
